function countChar(str, char) {
  return str.matchAll(new RegExp(char, 'g')).length || 0;
}

function countCharTyped(str, char) {
  const code = char.charCodeAt(0);
  const counts = new Uint32Array(1);
  for (const c of str) {
    if (c.charCodeAt(0) === code) counts[0]++;
  }
  return counts[0];
}
